def api_get(endpoint, params):
    params['token'] = TOKEN
    r = requests.get(f"{API}/{endpoint}", params=params)
    return r.json()

def api_upload(path, filepath):
    """Upload a file to Yemot - path must include filename e.g. ivr2:/2/2/1/M0000.wav"""
    with open(filepath, 'rb') as f:
        r = requests.post(
            f"{API}/UploadFile",
            data={'token': TOKEN, 'path': path},
            files={'upload': (os.path.basename(filepath), f)}
        )
        return r.json()

def upload_text(what, contents):
    """Upload text file (e.g. ext.ini)"""
    return api_get('UploadTextFile', {'what': what, 'contents': contents})

def create_extension(path):
    """Create/update an extension"""
    return api_get('UpdateExtension', {'path': path})

async def generate_tts(text, output_path):
    """Generate TTS audio using edge_tts"""
    communicate = edge_tts.Communicate(
        text,
        voice='he-IL-AvriNeural',
        rate='+12%',
        pitch='+4Hz',
        volume='+15%'
    )
    await communicate.save(output_path)

def mix_with_bg(tts_path, output_path):
    """Mix TTS with background music and convert to 8kHz WAV"""
    cmd = [
        'ffmpeg', '-y',
        '-i', tts_path,
        '-i', BG_MUSIC,
        '-filter_complex',
        '[0:a]volume=1.0[voice];[1:a]volume=0.3,aloop=loop=-1:size=2e+09[bg];[bg][voice]amix=inputs=2:duration=shortest:dropout_transition=2[out]',
        '-map', '[out]',
        '-ar', '8000', '-ac', '1', '-acodec', 'pcm_s16le',
        output_path
    ]
    r = subprocess.run(cmd, capture_output=True, text=True, timeout=120)
    if r.returncode != 0:
        print(f"  FFMPEG ERROR: {r.stderr[-300:]}")
        return False
    return True

def build_game_tts_text(game):
    """Build the TTS text for a game"""
    return (
        f"{game['name']}! "
        f"{game['desc']}. "
        f"\u05d0\u05d9\u05da \u05de\u05e9\u05d7\u05e7\u05d9\u05dd? {game['rules']} "
        f"{game['twist']} "
        f"\u05e9\u05d0\u05dc\u05d4 \u05dc\u05e1\u05d9\u05db\u05d5\u05dd: {game['reflection']} "
        f"\u05dc\u05de\u05e9\u05d7\u05e7 \u05d4\u05d1\u05d0, 1. \u05dc\u05d7\u05d6\u05e8\u05d4, \u05db\u05d5\u05db\u05d1\u05d9\u05ea."
    )

def build_category_menu_text(cat_name, games):
    """Build TTS text for category menu listing the 5 games"""
    text = f"\u05e7\u05d8\u05d2\u05d5\u05e8\u05d9\u05d4: {cat_name}! "
    for num, game in sorted(games.items()):
        text += f"\u05dc\u05d4\u05e7\u05e9\u05d9\u05d1 \u05dc\u05de\u05e9\u05d7\u05e7 {game['name']}, \u05d4\u05e7\u05d9\u05e9\u05d5 {num}. "
    text += "\u05dc\u05d7\u05d6\u05e8\u05d4, \u05db\u05d5\u05db\u05d1\u05d9\u05ea."
    return text

async def process_all():
    """Main processing loop"""
    total_generated = 0
    total_uploaded = 0
    errors = []

    for cat_path, cat_data in CATEGORIES.items():
        cat_name = cat_data['name']
        games = cat_data['games']
        print(f"\n{'='*60}")
        print(f"\u05e7\u05d8\u05d2\u05d5\u05e8\u05d9\u05d4: {cat_name} ({cat_path})")
        print(f"{'='*60}")

        # Process each game
        for game_num, game in sorted(games.items()):
            ext_path = f"ivr2:/{cat_path}/{game_num}"
            print(f"\n  [{game_num}] {game['name']}")

            # Create extension
            print(f"    Creating extension: {ext_path}")
            result = create_extension(ext_path)
            print(f"    -> {result.get('responseStatus', 'UNKNOWN')}")

            # Upload ext.ini
            print(f"    Uploading ext.ini")
            result = upload_text(f"{ext_path}/ext.ini", "type=playfile")
            print(f"    -> {result.get('responseStatus', 'UNKNOWN')}")

            # Generate TTS
            tts_text = build_game_tts_text(game)
            safe_name = f"{cat_path.replace('/', '_')}_{game_num}"
            tts_file = os.path.join(WORKDIR, f"tts_{safe_name}.mp3")
            wav_file = os.path.join(WORKDIR, f"game_{safe_name}.wav")

            print(f"    Generating TTS ({len(tts_text)} chars)...")
            try:
                await generate_tts(tts_text, tts_file)
                print(f"    TTS OK")
            except Exception as e:
                print(f"    TTS ERROR: {e}")
                errors.append(f"{ext_path}: TTS failed - {e}")
                continue

            # Mix with background
            print(f"    Mixing with background music...")
            if not mix_with_bg(tts_file, wav_file):
                errors.append(f"{ext_path}: ffmpeg mix failed")
                continue
            wav_size = os.path.getsize(wav_file)
            print(f"    Mixed OK ({wav_size:,} bytes)")
            total_generated += 1

            # Upload to Yemot
            upload_path = f"ivr2:/{cat_path}/{game_num}/M0000.wav"
            print(f"    Uploading to {upload_path}...")
            try:
                result = api_upload(upload_path, wav_file)
                status = result.get('responseStatus', 'UNKNOWN')
                print(f"    Upload: {status} {result}")
                if status == 'OK' or result.get('success'):
                    total_uploaded += 1
                else:
                    errors.append(f"{ext_path}: upload failed - {result}")
            except Exception as e:
                print(f"    Upload ERROR: {e}")
                errors.append(f"{ext_path}: upload failed - {e}")

        # Update category menu audio
        cat_ext_path = f"ivr2:/{cat_path}"
        print(f"\n  Updating category menu: {cat_ext_path}")
        create_extension(cat_ext_path)

        menu_text = build_category_menu_text(cat_name, games)
        safe_cat = cat_path.replace('/', '_')
        tts_menu = os.path.join(WORKDIR, f"tts_menu_{safe_cat}.mp3")
        wav_menu = os.path.join(WORKDIR, f"menu_{safe_cat}.wav")

        print(f"  Generating category menu TTS...")
        try:
            await generate_tts(menu_text, tts_menu)
            if mix_with_bg(tts_menu, wav_menu):
                upload_menu_path = f"ivr2:/{cat_path}/M0000.wav"
                print(f"  Uploading menu to {upload_menu_path}...")
                result = api_upload(upload_menu_path, wav_menu)
                status = result.get('responseStatus', 'UNKNOWN')
                print(f"  Menu upload: {status} {result}")
                if status == 'OK' or result.get('success'):
                    total_uploaded += 1
                    total_generated += 1
            else:
                errors.append(f"{cat_ext_path}: menu ffmpeg failed")
        except Exception as e:
            print(f"  Menu TTS ERROR: {e}")
            errors.append(f"{cat_ext_path}: menu TTS failed - {e}")

    # Summary
    print(f"\n{'='*60}")
    print(f"DONE!")
    print(f"  Generated: {total_generated} audio files")
    print(f"  Uploaded:  {total_uploaded} files")
    print(f"  Errors:    {len(errors)}")
    if errors:
        print(f"\nErrors:")
        for e in errors:
            print(f"  - {e}")
    print(f"{'='*60}")

if __name__ == '__main__':
    asyncio.run(process_all())
